-- Virtual module loader
local _modules = {}
local _loaded = {}

local function define(name, fn)
    _modules[name] = fn
end

local function _require(name)
    if _loaded[name] then return _loaded[name] end
    local fn = _modules[name]
    if not fn then error('module not found: ' .. name) end
    local result = fn(_require)
    _loaded[name] = result
    return result
end

local require = _require

-- ============================================================
-- Module: Util
