define("DrawList", function(require)
-- DrawList.lua — список draw-команд за кадр.
-- Виджеты и Window добавляют команды через Add* методы, в конце кадра
-- Renderer итерирует список и материализует в Drawing-объекты.
--
-- Каждая команда несёт clipRect (наследуется от текущего окна), Renderer
-- применяет CPU-отсечение против viewport окна.

local Util = require("Util")
local Vector2_new = Vector2.new

local DrawList = {}

export type DrawCommand = {
	-- тип примитива
	kind: string,
	-- область отсечения в абсолютных координатах экрана. nil = не отсекать.
	clipRect: Util.Rect?,
	-- payload
	p0: Vector2?,
	p1: Vector2?,
	p2: Vector2?,
	center: Vector2?,
	radius: number?,
	size: Vector2?,
	rounding: number?,
	color: Color3,
	thickness: number,
	filled: boolean,
	text: string?,
	font: Enum.Font?,
	textSize: number?,
}

export type DrawList = {
	commands: { DrawCommand },
	_clipStack: { Util.Rect },
	_activeClip: Util.Rect?,
}

function DrawList.new(): DrawList
	local self = {
		commands = {},
		_clipStack = {},
		_activeClip = nil,
	}
	setmetatable(self, { __index = DrawList })
	return self
end

function DrawList.Clear(self: DrawList)
	table.clear(self.commands)
	self._clipStack = {}
	self._activeClip = nil
end

-- ============================================================
-- Clip stack — нужен, чтобы виджеты вложенные в BeginChild
-- не вылезали за границы. MVP: просто Push/Pop.
-- ============================================================

function DrawList.PushClipRect(self: DrawList, rect: Util.Rect)
	self._clipStack[#self._clipStack + 1] = rect
	self._activeClip = rect
end

function DrawList.PopClipRect(self: DrawList)
	table.remove(self._clipStack)
	self._activeClip = self._clipStack[#self._clipStack]
end

-- ============================================================
-- Примитивы
-- ============================================================

function DrawList.AddLine(self: DrawList, p0: Vector2, p1: Vector2, color: Color3, thickness: number)
	self.commands[#self.commands + 1] = {
		kind = "Line",
		clipRect = self._activeClip,
		p0 = p0, p1 = p1,
		color = color,
		thickness = thickness or 1,
		filled = false,
	}
end

function DrawList.AddRect(self: DrawList, min: Vector2, max: Vector2, color: Color3, rounding: number?, thickness: number?)
	self.commands[#self.commands + 1] = {
		kind = "Rect",
		clipRect = self._activeClip,
		p0 = min, p1 = max,
		rounding = rounding or 0,
		color = color,
		thickness = thickness or 1,
		filled = false,
	}
end

function DrawList.AddRectFilled(self: DrawList, min: Vector2, max: Vector2, color: Color3, rounding: number?)
	self.commands[#self.commands + 1] = {
		kind = "RectFilled",
		clipRect = self._activeClip,
		p0 = min, p1 = max,
		rounding = rounding or 0,
		color = color,
		thickness = 0,
		filled = true,
	}
end

function DrawList.AddTriangle(self: DrawList, p0: Vector2, p1: Vector2, p2: Vector2, color: Color3, thickness: number?)
	self.commands[#self.commands + 1] = {
		kind = "Triangle",
		clipRect = self._activeClip,
		p0 = p0, p1 = p1, p2 = p2,
		color = color,
		thickness = thickness or 1,
		filled = false,
	}
end

function DrawList.AddTriangleFilled(self: DrawList, p0: Vector2, p1: Vector2, p2: Vector2, color: Color3)
	self.commands[#self.commands + 1] = {
		kind = "TriangleFilled",
		clipRect = self._activeClip,
		p0 = p0, p1 = p1, p2 = p2,
		color = color,
		thickness = 0,
		filled = true,
	}
end

function DrawList.AddCircle(self: DrawList, center: Vector2, radius: number, color: Color3, thickness: number?, _numSides: number?)
	-- _numSides сейчас не используется (Drawing рисует круг)
	self.commands[#self.commands + 1] = {
		kind = "Circle",
		clipRect = self._activeClip,
		center = center,
		radius = radius,
		color = color,
		thickness = thickness or 1,
		filled = false,
	}
end

function DrawList.AddCircleFilled(self: DrawList, center: Vector2, radius: number, color: Color3)
	self.commands[#self.commands + 1] = {
		kind = "CircleFilled",
		clipRect = self._activeClip,
		center = center,
		radius = radius,
		color = color,
		thickness = 0,
		filled = true,
	}
end

function DrawList.AddText(self: DrawList, pos: Vector2, color: Color3, text: string, font: Enum.Font?, textSize: number?)
	self.commands[#self.commands + 1] = {
		kind = "Text",
		clipRect = self._activeClip,
		p0 = pos,
		text = text,
		font = font or Enum.Font.Code,
		textSize = textSize or 14,
		color = color,
		thickness = 0,
		filled = false,
	}
end

-- ============================================================
-- Замер текста. Используем TextService.
-- ============================================================

local TextService = game:GetService("TextService")

local function measureText(text: string, font: Enum.Font, size: number): Vector2
	local ok, bounds = pcall(function()
		return TextService:GetTextSize(text, size, font, Vector2.new(math.huge, math.huge))
	end)
	if ok and bounds then return bounds end
	-- Fallback — грубая оценка
	return Vector2_new(#text * size * 0.55, size)
end

-- Публичный хелпер
function DrawList.CalcTextSize(_: DrawList, text: string, font: Enum.Font?, size: number?): Vector2
	return measureText(text, font or Enum.Font.Code, size or 14)
end

return DrawList

end)

-- ============================================================
-- Module: Renderer
-- ============================================================
define("Renderer", function(require)
-- Renderer.lua — материализация DrawList в Drawing-объекты.
--
-- Каждый кадр Core передаёт нам DrawList. Мы:
--   1. Идём по командам последовательно.
--   2. Берём объект из пула по индексу (или создаём новый).
--   3. Обновляем свойства объекта под команду.
--   4. Скрываем лишние объекты (если в этом кадре их меньше, чем в прошлом).
--
-- Никакого батчинга в Drawing API нет — каждый объект = отдельный
-- инстанс Drawing.new. Поэтому пул критичен для производительности.

local Util = require("Util")
local DrawList = require("DrawList")

local Renderer = {}

export type RenderPool = {
	-- Пулы по типам: Line, Rect, RectFilled, Triangle, TriangleFilled,
	-- Circle, CircleFilled, Text
	Line: { any },
	Rect: { any },
	RectFilled: { any },
	Triangle: { any },
	TriangleFilled: { any },
	Circle: { any },
	CircleFilled: { any },
	Text: { any },

	-- Счётчики использованных объектов в текущем кадре
	_used: { [string]: number },
}

-- Безопасное создание Drawing-объекта. Не все эксплойты
-- предоставляют одинаковое API.
local function newDrawing(kind: string): any
	local ok, obj = pcall(Drawing.new, kind)
	if not ok or not obj then
		error("Renderer: Drawing.new(\"" .. kind .. "\") failed — Drawing API unavailable")
	end
	obj.Visible = false
	return obj
end

function Renderer.new(): RenderPool
	local self = {
		Line = {},
		Rect = {},
		RectFilled = {},
		Triangle = {},
		TriangleFilled = {},
		Circle = {},
		CircleFilled = {},
		Text = {},

		_used = {},
	}
	setmetatable(self, { __index = Renderer })
	return self
end

-- Получить объект из пула (или создать). Все пулы растут по необходимости.
local function getOrCreate(pool: { any }, kind: string, idx: number): any
	local obj = pool[idx]
	if not obj then
		obj = newDrawing(kind)
		pool[idx] = obj
	end
	return obj
end

-- Скрывает неиспользуемые объекты в пуле начиная с индекса fromIdx
local function hideTail(pool: { any }, fromIdx: number)
	for i = fromIdx, #pool do
		local obj = pool[i]
		if obj and obj.Visible then
			obj.Visible = false
		end
	end
end

-- ============================================================
-- Главная точка входа: отрисовать DrawList
-- ============================================================

function Renderer.Render(self: RenderPool, drawList: DrawList.DrawList)
	-- Сбросить счётчики использованных
	self._used = {}

	local cmds = drawList.commands
	for i = 1, #cmds do
		local cmd = cmds[i]
		local used = self._used[cmd.kind] or 0
		used = used + 1
		self._used[cmd.kind] = used

		-- CPU-clip: пропускаем команды, не входящие в clipRect.
		-- Для Text мы всё равно создаём/обновляем, но ставим Visible=false
		-- (иначе риски протечки в эксплойтах с прокси-объектами).
		local clip = cmd.clipRect

		if cmd.kind == "Line" then
			self:_renderLine(used, cmd, clip)
		elseif cmd.kind == "Rect" then
			self:_renderRect(used, cmd, clip)
		elseif cmd.kind == "RectFilled" then
			self:_renderRectFilled(used, cmd, clip)
		elseif cmd.kind == "Triangle" then
			self:_renderTriangle(used, cmd, clip)
		elseif cmd.kind == "TriangleFilled" then
			self:_renderTriangleFilled(used, cmd, clip)
		elseif cmd.kind == "Circle" then
			self:_renderCircle(used, cmd, clip)
		elseif cmd.kind == "CircleFilled" then
			self:_renderCircleFilled(used, cmd, clip)
		elseif cmd.kind == "Text" then
			self:_renderText(used, cmd, clip)
		end
	end

	-- Скрыть хвосты во всех пулах
	hideTail(self.Line,        (self._used.Line or 0) + 1)
	hideTail(self.Rect,        (self._used.Rect or 0) + 1)
	hideTail(self.RectFilled,  (self._used.RectFilled or 0) + 1)
	hideTail(self.Triangle,    (self._used.Triangle or 0) + 1)
	hideTail(self.TriangleFilled, (self._used.TriangleFilled or 0) + 1)
	hideTail(self.Circle,      (self._used.Circle or 0) + 1)
	hideTail(self.CircleFilled,(self._used.CircleFilled or 0) + 1)
	hideTail(self.Text,        (self._used.Text or 0) + 1)
end

-- ============================================================
-- Вспомогательные функции для каждого типа примитива
-- ============================================================

function Renderer._renderLine(self: RenderPool, idx: number, cmd: any, clip: any)
	local obj = getOrCreate(self.Line, "Line", idx)
	if not cmd.p0 or not cmd.p1 then obj.Visible = false; return end

	local p0, p1 = cmd.p0, cmd.p1
	if clip then
		p0, p1 = Util.RectClipLine(clip, p0, p1)
	end

	obj.From = p0
	obj.To = p1
	obj.Color = cmd.color
	obj.Thickness = cmd.thickness
	obj.Visible = true
end

function Renderer._renderRect(self: RenderPool, idx: number, cmd: any, clip: any)
	local obj = getOrCreate(self.Rect, "Square", idx)
	if not cmd.p0 or not cmd.p1 then obj.Visible = false; return end

	local p0, p1 = cmd.p0, cmd.p1
	if clip then
		local clipped = Util.RectClip(
			{ min = p0, max = p1 },
			clip
		)
		if not clipped then obj.Visible = false; return end
		p0, p1 = clipped.min, clipped.max
	end

	obj.Position = p0
	obj.Size = Vector2.new(p1.X - p0.X, p1.Y - p0.Y)
	obj.Color = cmd.color
	obj.Thickness = cmd.thickness
	obj.Filled = false
	obj.Visible = true
end

function Renderer._renderRectFilled(self: RenderPool, idx: number, cmd: any, clip: any)
	local obj = getOrCreate(self.RectFilled, "Square", idx)
	if not cmd.p0 or not cmd.p1 then obj.Visible = false; return end

	local p0, p1 = cmd.p0, cmd.p1
	if clip then
		local clipped = Util.RectClip(
			{ min = p0, max = p1 },
			clip
		)
		if not clipped then obj.Visible = false; return end
		p0, p1 = clipped.min, clipped.max
	end

	obj.Position = p0
	obj.Size = Vector2.new(p1.X - p0.X, p1.Y - p0.Y)
	obj.Color = cmd.color
	obj.Filled = true
	obj.Thickness = 0
	obj.Visible = true
end

function Renderer._renderTriangle(self: RenderPool, idx: number, cmd: any, clip: any)
	-- Drawing API не имеет примитива "треугольник" напрямую.
	-- Раскладываем на 3 линии.
	if not cmd.p0 or not cmd.p1 or not cmd.p2 then return end
	local pts = { cmd.p0, cmd.p1, cmd.p2 }
	for i = 1, 3 do
		local lineIdx = (idx - 1) * 3 + i
		local obj = getOrCreate(self.Triangle, "Line", lineIdx)
		local a, b = pts[i], pts[(i % 3) + 1]
		if clip then
			a, b = Util.RectClipLine(clip, a, b)
		end
		obj.From = a
		obj.To = b
		obj.Color = cmd.color
		obj.Thickness = cmd.thickness
		obj.Visible = true
	end
	-- Скрыть лишние, если было больше линий, чем сейчас
	local used = (self._used.Triangle or 0) * 3
	for i = used + 1, #self.Triangle do
		local obj = self.Triangle[i]
		if obj and obj.Visible then obj.Visible = false end
	end
end

function Renderer._renderTriangleFilled(self: RenderPool, idx: number, cmd: any, clip: any)
	if not cmd.p0 or not cmd.p1 or not cmd.p2 then return end
	-- Рисуем через Quad (Square) как fallback. MVP: пропускаем clip для triangle.
	local obj = getOrCreate(self.TriangleFilled, "Square", idx)
	-- Bounding box
	local minX = math.min(cmd.p0.X, cmd.p1.X, cmd.p2.X)
	local minY = math.min(cmd.p0.Y, cmd.p1.Y, cmd.p2.Y)
	local maxX = math.max(cmd.p0.X, cmd.p1.X, cmd.p2.X)
	local maxY = math.max(cmd.p0.Y, cmd.p1.Y, cmd.p2.Y)
	obj.Position = Vector2.new(minX, minY)
	obj.Size = Vector2.new(maxX - minX, maxY - minY)
	obj.Color = cmd.color
	obj.Filled = true
	obj.Visible = true
end

function Renderer._renderCircle(self: RenderPool, idx: number, cmd: any, clip: any)
	local obj = getOrCreate(self.Circle, "Circle", idx)
	if not cmd.center then obj.Visible = false; return end

	obj.Position = cmd.center
	obj.Radius = cmd.radius
	obj.Color = cmd.color
	obj.Thickness = cmd.thickness
	obj.Filled = false
	obj.NumSides = 30
	obj.Visible = true
end

function Renderer._renderCircleFilled(self: RenderPool, idx: number, cmd: any, clip: any)
	local obj = getOrCreate(self.CircleFilled, "Circle", idx)
	if not cmd.center then obj.Visible = false; return end

	obj.Position = cmd.center
	obj.Radius = cmd.radius
	obj.Color = cmd.color
	obj.Filled = true
	obj.Thickness = 0
	obj.NumSides = 30
	obj.Visible = true
end

function Renderer._renderText(self: RenderPool, idx: number, cmd: any, clip: any)
	local obj = getOrCreate(self.Text, "Text", idx)
	if not cmd.p0 or not cmd.text then obj.Visible = false; return end

	obj.Position = cmd.p0
	obj.Text = cmd.text
	obj.Color = cmd.color
	obj.Size = cmd.textSize or 14
	obj.Font = Renderer._fontToNumber(cmd.font)
	obj.Center = false
	obj.Outline = false
	obj.Visible = true

	-- Clip для текста — пока простой: скрываем если центр за пределами.
	-- Правильная реализация потребует TextBounds-aware проверки, оставим на следующий шаг.
end

-- Конвертация Enum.Font в число, которое ждёт Drawing API.
-- Drawing API Font: 0=UI, 1=System, 2=Plex, 3=Monospace, 4=Arial, 5=Highway,
-- 6=SourceSans, 7=SourceSansBold
--
-- Важно: не все Enum.Font значения существуют во всех версиях Roblox/эксплойтов.
-- Доступ к Enum.Font.UI при отсутствии члена бросает ошибку, поэтому
-- ищем шрифт по имени строки ВНУТРИ pcall.
local FONT_MAP = {}

-- Пары {имя, номер}. Имя ищется через Enum.Font[name] внутри pcall.
local FONT_NAMES = {
	{ "UI", 0 },
	{ "System", 1 },
	{ "Plex", 2 },
	{ "Monospace", 3 },
	{ "Arial", 4 },
	{ "ArialBold", 4 },
	{ "Highway", 5 },
	{ "SourceSans", 6 },
	{ "SourceSansBold", 7 },
	{ "Code", 3 },
	{ "Roboto", 6 },
	{ "RobotoMono", 3 },
	{ "Gotham", 6 },
	{ "GothamMedium", 6 },
	{ "GothamBold", 7 },
	{ "GothamBlack", 7 },
	{ "Montserrat", 6 },
	{ "MontserratBold", 7 },
	{ "Baloo", 6 },
	{ "BalooBold", 7 },
	{ "Bangers", 6 },
	{ "Creepster", 6 },
	{ "DenkOne", 6 },
	{ "Fondamento", 6 },
	{ "FredokaOne", 6 },
	{ "Jura", 6 },
	{ "JuraBold", 7 },
	{ "Kalam", 6 },
	{ "LuckiestGuy", 6 },
	{ "Merriweather", 6 },
	{ "Michroma", 6 },
	{ "Nunito", 6 },
	{ "Oswald", 6 },
	{ "OswaldBold", 7 },
	{ "PatrickHand", 6 },
	{ "PermanentMarker", 6 },
	{ "RobotoCondensed", 6 },
	{ "RobotoCondensedBold", 7 },
	{ "Spectral", 6 },
	{ "SpectralBold", 7 },
	{ "TitilliumWeb", 6 },
	{ "TitilliumWebBold", 7 },
	{ "ZillaSlab", 6 },
	{ "ZillaSlabBold", 7 },
}

local function buildFontMap()
	for i = 1, #FONT_NAMES do
		local entry = FONT_NAMES[i]
		local name, num = entry[1], entry[2]
		local ok, font = pcall(function()
			return Enum.Font[name]
		end)
		if ok and font then
			FONT_MAP[font] = num
		end
	end
end

buildFontMap()

function Renderer._fontToNumber(font: any): number
	if type(font) == "number" then return font end
	if not font then return 0 end
	local n = FONT_MAP[font]
	if n then return n end
	-- Fallback: EnumItem.Value
	local ok, v = pcall(function()
		return font.Value
	end)
	if ok and type(v) == "number" then return v end
	return 0
end

-- ============================================================
-- Destroy — освободить все Drawing-объекты
-- ============================================================

function Renderer.Destroy(self: RenderPool)
	for _, pool in ipairs({
		self.Line, self.Rect, self.RectFilled,
		self.Triangle, self.TriangleFilled,
		self.Circle, self.CircleFilled, self.Text,
	}) do
		for i = 1, #pool do
			local obj = pool[i]
			if obj then
				pcall(function()
					obj:Remove()
				end)
			end
		end
	end

	self.Line = {}
	self.Rect = {}
	self.RectFilled = {}
	self.Triangle = {}
	self.TriangleFilled = {}
	self.Circle = {}
	self.CircleFilled = {}
	self.Text = {}
end

return Renderer

end)

-- ============================================================
-- Module: Layout
-- ============================================================
define("Layout", function(require)
-- Layout.lua — auto-layout курсор, ItemRect, SameLine / Indent / Spacing.
--
-- Каждый раз когда виджет хочет знать «где меня рисовать», он читает
-- Layout.cursor и Layout.contentMax. После отрисовки виджет вызывает
-- Layout.ItemSize(), который сдвигает курсор вниз на свою высоту + spacing.

local Util = require("Util")
local Vector2_new = Vector2.new

local Layout = {}

export type Layout = {
	-- Левый верхний угол клиентской области окна (в абсолютных координатах)
	origin: Vector2,
	-- Курсор — куда класть следующий виджет
	cursor: Vector2,
	-- Максимальная занятая область (для auto-size окна и scroll)
	contentMin: Vector2,
	contentMax: Vector2,
	-- Сколько раз в этом кадре вызывалась SameLine (для переключения строки)
	lineHeight: number,
	lineStartPos: Vector2,
	-- Текущий отступ (Indent)
	indentX: number,
	-- ItemRect последнего виджета (для IsItemHovered/Active)
	lastItemRect: Util.Rect,
	-- Для SameLine: флаг «следующий виджет должен встать в ту же строку»
	sameLine: boolean,
	-- Текущая ширина строки (для ширины виджета по умолчанию)
	lineWidth: number,
}

function Layout.new(): Layout
	local self = {
		origin = Vector2_new(0, 0),
		cursor = Vector2_new(0, 0),
		contentMin = Vector2_new(0, 0),
		contentMax = Vector2_new(0, 0),
		lineHeight = 0,
		lineStartPos = Vector2_new(0, 0),
		indentX = 0,
		lastItemRect = Util.Rect(0, 0, 0, 0),
		sameLine = false,
		lineWidth = 0,
	}
	setmetatable(self, { __index = Layout })
	return self
end

-- Сброс к началу клиентской области окна.
function Layout.Reset(self: Layout, origin: Vector2)
	self.origin = origin
	self.cursor = Vector2_new(origin.X + self.indentX, origin.Y)
	self.contentMin = origin
	self.contentMax = origin
	self.lineHeight = 0
	self.lineStartPos = self.cursor
	self.sameLine = false
	self.lineWidth = 0
end

-- Сдвинуть курсор на новую строку (если не SameLine)
function Layout.NewLine(self: Layout, spacing: Vector2)
	self.cursor = Vector2_new(self.origin.X + self.indentX, self.cursor.Y + self.lineHeight + spacing.Y)
	self.lineHeight = 0
	self.lineStartPos = self.cursor
	self.sameLine = false
	self.lineWidth = 0
end

-- SameLine: следующий виджет в той же строке
function Layout.SameLine(self: Layout, offsetX: number?, spacingW: number?)
	if not self.sameLine then
		-- Закрыть предыдущую строку: cursor уже правее последнего виджета
		self.sameLine = true
	end
	local dx = (offsetX or 0) + (spacingW or 8)
	self.cursor = Vector2_new(self.cursor.X + dx, self.lineStartPos.Y)
end

function Layout.Indent(self: Layout, w: number)
	self.indentX = self.indentX + w
	self.cursor = Vector2_new(self.cursor.X + w, self.cursor.Y)
end

function Layout.Unindent(self: Layout, w: number)
	self.indentX = self.indentX - w
	if self.indentX < 0 then self.indentX = 0 end
	self.cursor = Vector2_new(self.cursor.X - w, self.cursor.Y)
	if self.cursor.X < self.origin.X then self.cursor = Vector2_new(self.origin.X, self.cursor.Y) end
end

-- Виджет должен вызвать ItemSize после отрисовки.
-- size — размер виджета (width, height).
function Layout.ItemSize(self: Layout, size: Vector2, spacing: Vector2)
	local pos = self.cursor

	-- Обновить content bounds
	if pos.X < self.contentMin.X then self.contentMin = Vector2_new(pos.X, self.contentMin.Y) end
	if pos.Y < self.contentMin.Y then self.contentMin = Vector2_new(self.contentMin.X, pos.Y) end
	if pos.X + size.X > self.contentMax.X then self.contentMax = Vector2_new(pos.X + size.X, self.contentMax.Y) end
	if pos.Y + size.Y > self.contentMax.Y then self.contentMax = Vector2_new(self.contentMax.X, pos.Y + size.Y) end

	-- Обновить lastItemRect (для IsItemHovered/Active)
	self.lastItemRect = Util.RectFromMinMax(pos, Vector2_new(pos.X + size.X, pos.Y + size.Y))

	-- Обновить line height
	if size.Y > self.lineHeight then
		self.lineHeight = size.Y
	end

	-- Сдвинуть курсор
	if self.sameLine then
		self.cursor = Vector2_new(pos.X + size.X + spacing.X, pos.Y)
		self.lineWidth = self.lineWidth + size.X + spacing.X
	else
		self.cursor = Vector2_new(self.origin.X + self.indentX, pos.Y + size.Y + spacing.Y)
		self.lineHeight = size.Y
		self.lineStartPos = Vector2_new(self.origin.X + self.indentX, pos.Y)
	end
end

-- Принудительно выставить lastItemRect (виджет сам посчитал позицию)
function Layout.SetItemRect(self: Layout, rect: Util.Rect)
	self.lastItemRect = rect
end

return Layout

end)

-- ============================================================
-- Module: Window
-- ============================================================
define("Window", function(require)
-- Window.lua — оконная система.
-- Begin(name, opt) → End().
-- Окно хранит позицию/размер между кадрами (stateful), поддерживает:
--   - drag за title bar
--   - resize за правый нижний угол
--   - collapse/expand
--   - focus (ZIndex): последнее кликнутое окно наверх
--   - clipping дочерних виджетов по клиентской области

local Util    = require("Util")
local Style   = require("Style")
local Layout  = require("Layout")
local DrawList = require("DrawList")
local Vector2_new = Vector2.new

local Window = {}

export type WindowOptions = {
	pos: Vector2?,
	size: Vector2?,
	flags: { [string]: boolean }?,
}

export type Window = {
	-- Идентификация
	name: string,
	id: number,

	-- Позиция / размер (в абсолютных координатах экрана)
	pos: Vector2,
	size: Vector2,

	-- Состояние
	collapsed: boolean,
	focused: boolean,
	focusOrder: number, -- больше = выше

	-- Временное состояние в течение кадра
	flags: { [string]: boolean },
	appearing: boolean, -- первый кадр после открытия
	_titleBarRect: Util.Rect,
	_resizeGripRect: Util.Rect,

	-- Клиентская область (где рисуются виджеты)
	_clientRect: Util.Rect,

	-- Состояние drag/resize
	_dragging: boolean,
	_dragOffset: Vector2,
	_resizing: boolean,
	_resizeStartSize: Vector2,
	_resizeStartMouse: Vector2,

	-- Layout окна
	layout: Layout.Layout,
}

-- Хранилище окон по имени (stateful между кадрами)
-- Ключ — name (string), значение — Window
local _windows = {}
local _order = {} -- упорядоченный список (z-order)
local _focusCounter = 0

-- Найти окно по имени (создать если не существует)
function Window.GetOrCreate(name: string, defaultPos: Vector2, defaultSize: Vector2): Window
	local w = _windows[name]
	if w then return w end

	w = {
		name = name,
		id = Util.HashStr(name),
		pos = defaultPos,
		size = defaultSize,
		collapsed = false,
		focused = false,
		focusOrder = 0,
		flags = {},
		appearing = true,
		_titleBarRect = Util.Rect(0, 0, 0, 0),
		_resizeGripRect = Util.Rect(0, 0, 0, 0),
		_clientRect = Util.Rect(0, 0, 0, 0),
		_dragging = false,
		_dragOffset = Vector2_new(0, 0),
		_resizing = false,
		_resizeStartSize = Vector2_new(0, 0),
		_resizeStartMouse = Vector2_new(0, 0),
		layout = Layout.new(),
	}
	_windows[name] = w
	table.insert(_order, w)
	return w
end

function Window.GetAll(): { Window }
	return _order
end

function Window.Get(name: string): Window?
	return _windows[name]
end

-- Вызывается Core.Clear()
function Window.ClearOrder()
	table.clear(_order)
	-- _windows оставляем — stateful данные окон переживут перезагрузку
end

-- ============================================================
-- Begin / End
-- ============================================================

local Core_ref -- forward-объявление, будет установлен Core.lua после загрузки
local function setCoreRef(core)
	Core_ref = core
end
Window._setCoreRef = setCoreRef

function Window.Begin(drawList: DrawList.DrawList, style: Style.ImGuiStyle, input: any, name: string, opt: WindowOptions?): Window
	local w = Window.GetOrCreate(name, opt and opt.pos or Vector2_new(100, 100), opt and opt.size or Vector2_new(300, 200))

	-- Применить флаги
	w.flags = (opt and opt.flags) or {}
	w.appearing = (w.appearing == true)

	-- Если окно уже коллапсировано, всё равно рисуем title bar

	-- Принудительный размер если есть в опциях
	if opt and opt.size and w.appearing then
		w.size = opt.size
	end
	if opt and opt.pos and w.appearing then
		w.pos = opt.pos
	end

	-- Минимальный размер
	if w.size.X < style.WindowMinSize.X then w.size = Vector2_new(style.WindowMinSize.X, w.size.Y) end
	if w.size.Y < style.WindowMinSize.Y then w.size = Vector2_new(w.size.X, style.WindowMinSize.Y) end

	-- Title bar rect
	local titleHeight = 24
	w._titleBarRect = Util.Rect(w.pos.X, w.pos.Y, w.size.X, titleHeight)

	-- Resize grip rect (правый нижний угол, 12x12)
	w._resizeGripRect = Util.Rect(w.pos.X + w.size.X - 12, w.pos.Y + w.size.Y - 12, 12, 12)

	-- Client rect (внутренняя область окна)
	local pad = style.WindowPadding
	local clientX = w.pos.X + pad.X
	local clientY = w.pos.Y + titleHeight + pad.Y
	local clientW = w.size.X - pad.X * 2
	local clientH = w.size.Y - titleHeight - pad.Y * 2
	if clientW < 0 then clientW = 0 end
	if clientH < 0 then clientH = 0 end
	w._clientRect = Util.Rect(clientX, clientY, clientW, clientH)

	-- Layout reset
	w.layout:Reset(Vector2_new(clientX, clientY))

	-- Push clip rect
	drawList:PushClipRect(w._clientRect)

	-- Input handling: focus on click
	if input.mouseClicked and Util.RectContains(w._titleBarRect, input.mousePos) then
		w.focused = true
		w.focusOrder = _focusCounter + 1
		_focusCounter = _focusCounter + 1
	end

	-- Drag handling
	if not w.flags.NoMove then
		if not w._dragging and input.mouseClicked and Util.RectContains(w._titleBarRect, input.mousePos) then
			w._dragging = true
			w._dragOffset = Vector2_new(input.mousePos.X - w.pos.X, input.mousePos.Y - w.pos.Y)
		end
		if w._dragging then
			w.pos = Vector2_new(input.mousePos.X - w._dragOffset.X, input.mousePos.Y - w._dragOffset.Y)
			if not input.mouseDown then
				w._dragging = false
			end
		end
	end

	-- Resize handling
	if not w.flags.NoResize and not w.collapsed then
		if not w._resizing and input.mouseClicked and Util.RectContains(w._resizeGripRect, input.mousePos) then
			w._resizing = true
			w._resizeStartSize = w.size
			w._resizeStartMouse = input.mousePos
		end
		if w._resizing then
			local delta = Vector2_new(input.mousePos.X - w._resizeStartMouse.X, input.mousePos.Y - w._resizeStartMouse.Y)
			w.size = Vector2_new(
				Util.Max(w._resizeStartSize.X + delta.X, style.WindowMinSize.X),
				Util.Max(w._resizeStartSize.Y + delta.Y, style.WindowMinSize.Y)
			)
			if not input.mouseDown then
				w._resizing = false
			end
		end
	end

	-- Рисуем окно (фон + title + borders)
	Window._DrawWindow(drawList, style, w)

	w.appearing = false
	return w
end

function Window._DrawWindow(drawList: DrawList.DrawList, style: Style.ImGuiStyle, w: Window)
	local col = style.Colors
	local round = style.WindowRounding
	local border = style.WindowBorderSize

	local p0 = w.pos
	local p1 = Vector2_new(w.pos.X + w.size.X, w.pos.Y + w.size.Y)

	-- Фон
	drawList:AddRectFilled(p0, p1, col.WindowBg, round)

	-- Title bar
	local titleP0 = p0
	local titleP1 = Vector2_new(p1.X, p0.Y + 24)
	drawList:AddRectFilled(titleP0, titleP1, w.focused and col.TitleBgActive or col.TitleBg, round)

	-- Border
	if border > 0 then
		drawList:AddRect(p0, p1, col.Border, round, border)
	end

	-- Title text
	drawList:AddText(
		Vector2_new(p0.X + style.WindowPadding.X, p0.Y + (24 - 14) / 2),
		col.Text,
		w.name,
		Enum.Font.Code,
		14
	)

	-- Resize grip (визуальная подсказка)
	if not w.flags.NoResize and not w.collapsed then
		local gripColor = Util.RectContains(w._resizeGripRect, Vector2_new(0, 0)) and col.ResizeGripHovered or col.ResizeGrip
		-- Маленький треугольник в углу
		local gx, gy = p1.X, p1.Y
		drawList:AddTriangleFilled(
			Vector2_new(gx - 12, gy),
			Vector2_new(gx, gy),
			Vector2_new(gx, gy - 12),
			gripColor
		)
	end
end

function Window.End(drawList: DrawList.DrawList)
	drawList:PopClipRect()
end

-- ============================================================
-- Хелперы для виджетов
-- ============================================================

-- Получить текущее окно (top of stack). Реализуется через Core.currentWindow.
function Window.Current(): Window?
	if Core_ref and Core_ref.currentWindow then
		return Core_ref.currentWindow
	end
	return nil
end

return Window

end)

-- ============================================================
-- Module: Core
-- ============================================================
define("Core", function(require)
-- Core.lua — глобальный контекст ImGui.
-- Хранит текущее окно, DrawList, Style, Input, Renderer.
-- BeginFrame() → (юзерский код Begin/End/Widgets) → EndFrame().

local Util     = require("Util")
local Style    = require("Style")
local Input    = require("Input")
local DrawList = require("DrawList")
local Renderer = require("Renderer")
local Window   = require("Window")

local Core = {}

export type Context = {
	style: Style.ImGuiStyle,
	input: Input.InputState,
	renderer: RenderPool, -- Renderer.RenderPool
	drawList: DrawList.DrawList,

	-- Текущее окно (top of stack)
	currentWindow: Window.Window?,

	-- Фрейм-стейт
	frame: number,
	framed: boolean, -- между BeginFrame и EndFrame
}

-- Forward-объявление типа (Renderer.RenderPool не экспортируется через type)
type RenderPool = any

local _ctx = nil

function Core.new(): Context
	local ctx = {
		style = Style.CreateDark(),
		input = Input.new(),
		renderer = Renderer.new(),
		drawList = DrawList.new(),
		currentWindow = nil,
		frame = 0,
		framed = false,
	}
	Window._setCoreRef(ctx)
	return ctx
end

-- Singleton accessor. Core.new() вызывает пользователь.
function Core.Get(): Context
	if not _ctx then
		_ctx = Core.new()
		Input.Init(_ctx.input)
	end
	return _ctx
end

function Core.BeginFrame(self: Context)
	self.frame += 1
	self.framed = true
	self.currentWindow = nil

	Input.BeginFrame(self.input)
	DrawList.Clear(self.drawList)
end

function Core.EndFrame(self: Context)
	-- Отсортировать окна по focusOrder перед рендером (для z-order).
	-- Окна с большим focusOrder рисуются последними (поверх).
	-- Однако DrawList уже накапливает команды в порядке Begin() вызовов —
	-- что соответствует z-order'у, если юзер вызывает Begin в нужном порядке.
	-- Для простоты MVP: порядок рисования = порядок Begin в кадре.
	-- Фокус меняет только визуальное состояние (title bar color).

	Renderer.Render(self.renderer, self.drawList)

	self.framed = false
	self.currentWindow = nil
end

function Core.Destroy(self: Context)
	Input.Destroy(self.input)
	Renderer.Destroy(self.renderer)
	if _ctx == self then
		_ctx = nil
	end
end

return Core

end)

-- ============================================================
-- Module: Widgets
-- ============================================================
define("Widgets", function(require)
-- Widgets.lua — виджеты MVP.
-- Button, Text, Checkbox, Separator, Spacing.
-- Каждый виджет:
--   1. Считывает Layout.currentWindow.layout для позиции.
--   2. Пушит draw-команды в DrawList.
--   3. Делает hit-test против input.mousePos / mouseDown.
--   4. Вызывает Layout.itemSize() для авто-layout.

local Util     = require("Util")
local DrawList = require("DrawList")
local Window   = require("Window")
local Vector2_new = Vector2.new

local Widgets = {}

-- ============================================================
-- Внутренние хелперы
-- ============================================================

-- Получить текущий контекст (Core). Через Window._setCoreRef мы зарегистрировали его.
local function ctx()
	return Window.Current() and (Window.Current() :: any)._coreRef or nil
end

-- Более надёжный путь: получить окно и его layout/drawList/style/input.
local function currentWindow()
	local w = Window.Current()
	if not w then
		error("Widgets: called outside of Begin/End block")
	end
	return w
end

-- Доступ к глобальному контексту через Window._getCore()
-- (устанавливается в Core.new через _setCoreRef).
local _coreRef = nil
function Widgets._setCoreRef(c)
	_coreRef = c
end

local function core()
	if not _coreRef then error("Widgets: core not initialized") end
	return _coreRef
end

-- Hit-test: мышь внутри прямоугольника?
local function mouseInRect(rect: Util.Rect, mousePos: Vector2): boolean
	return Util.RectContains(rect, mousePos)
end

-- ============================================================
-- Button
-- ============================================================

function Widgets.Button(label: string, size: Vector2?): boolean
	local w = currentWindow()
	local c = core()
	local style = c.style
	local input = c.input
	local drawList = c.drawList

	-- Размер кнопки
	local btnSize = size or Vector2_new(0, 0)
	if btnSize.X == 0 then btnSize = Vector2_new(80, 0) end
	if btnSize.Y == 0 then btnSize = Vector2_new(btnSize.X, 22) end

	-- Позиция: берём из layout
	local pos = w.layout.cursor
	local rect = Util.Rect(pos.X, pos.Y, btnSize.X, btnSize.Y)

	-- Состояние
	local hovered = mouseInRect(rect, input.mousePos)
	local active = hovered and input.mouseDown
	local pressed = hovered and input.mouseClicked

	-- Цвет
	local col = style.Colors
	local color
	if active then color = col.ButtonActive
	elseif hovered then color = col.ButtonHovered
	else color = col.Button end

	-- Рисуем
	local p0 = rect.min
	local p1 = rect.max
	drawList:AddRectFilled(p0, p1, color, style.FrameRounding)

	if style.FrameBorderSize > 0 then
		drawList:AddRect(p0, p1, col.Border, style.FrameRounding, style.FrameBorderSize)
	end

	-- Текст по центру
	local textSize = Vector2_new(0, 14)
	local ok, TextService = pcall(function() return game:GetService("TextService") end)
	if ok then
		local bounds = TextService:GetTextSize(label, 14, Enum.Font.Code, Vector2_new(math.huge, math.huge))
		textSize = bounds
	end

	local textX = p0.X + (btnSize.X - textSize.X) * style.ButtonTextAlign.X
	local textY = p0.Y + (btnSize.Y - textSize.Y) * style.ButtonTextAlign.Y
	drawList:AddText(Vector2_new(textX, textY), col.Text, label, Enum.Font.Code, 14)

	-- Layout: сдвиг курсора
	w.layout:ItemSize(btnSize, style.ItemSpacing)

	return pressed
end

-- ============================================================
-- Text
-- ============================================================

function Widgets.Text(s: string)
	local w = currentWindow()
	local c = core()
	local style = c.style
	local drawList = c.drawList

	-- Замер текста
	local textSize = Vector2_new(0, 14)
	local ok, TextService = pcall(function() return game:GetService("TextService") end)
	if ok then
		local bounds = TextService:GetTextSize(s, 14, Enum.Font.Code, Vector2_new(math.huge, math.huge))
		textSize = bounds
	end

	local pos = w.layout.cursor
	drawList:AddText(pos, style.Colors.Text, s, Enum.Font.Code, 14)

	w.layout:ItemSize(textSize, style.ItemSpacing)
end

-- ============================================================
-- Checkbox
-- ============================================================

function Widgets.Checkbox(label: string, value: { value: boolean }): boolean
	local w = currentWindow()
	local c = core()
	local style = c.style
	local input = c.input
	local drawList = c.drawList

	-- Размер чекбокса: квадрат style.GrabMinSize x style.GrabMinSize
	local box = style.GrabMinSize
	local boxSize = Vector2_new(box, box)

	-- Замер текста для общей ширины
	local textSize = Vector2_new(0, 14)
	local ok, TextService = pcall(function() return game:GetService("TextService") end)
	if ok then
		local bounds = TextService:GetTextSize(label, 14, Enum.Font.Code, Vector2_new(math.huge, math.huge))
		textSize = bounds
	end

	local totalW = box + style.ItemInnerSpacing.X + textSize.X
	local totalH = math.max(box, textSize.Y)

	local pos = w.layout.cursor
	-- total rect для hit-test
	local rect = Util.Rect(pos.X, pos.Y, totalW, totalH)
	local hovered = mouseInRect(rect, input.mousePos)

	-- Box rect
	local boxRect = Util.Rect(pos.X, pos.Y + (totalH - box) / 2, box, box)

	-- Toggle on click
	local toggled = false
	if hovered and input.mouseClicked then
		value.value = not value.value
		toggled = true
	end

	local col = style.Colors
	-- Box bg
	local boxColor
	if value.value then
		boxColor = col.CheckMark
	else
		boxColor = hovered and col.ButtonHovered or col.Button
	end
	drawList:AddRectFilled(boxRect.min, boxRect.max, boxColor, style.GrabRounding)

	if style.FrameBorderSize > 0 then
		drawList:AddRect(boxRect.min, boxRect.max, col.Border, style.GrabRounding, style.FrameBorderSize)
	end

	-- Checkmark (если value.value)
	if value.value then
		-- Маленькая галочка: линия из левого-нижнего в центр и в правый-верхний угол
		local pad = 2
		local a = Vector2_new(boxRect.min.X + pad, boxRect.min.Y + box / 2)
		local b = Vector2_new(boxRect.min.X + box / 2, boxRect.max.Y - pad)
		local cc = Vector2_new(boxRect.max.X - pad, boxRect.min.Y + pad)
		drawList:AddLine(a, b, col.Text, 2)
		drawList:AddLine(b, cc, col.Text, 2)
	end

	-- Label
	drawList:AddText(
		Vector2_new(pos.X + box + style.ItemInnerSpacing.X, pos.Y + (totalH - textSize.Y) / 2),
		col.Text, label, Enum.Font.Code, 14
	)

	w.layout:ItemSize(Vector2_new(totalW, totalH), style.ItemSpacing)

	return toggled
end

-- ============================================================
-- Separator — горизонтальная линия на всю ширину окна
-- ============================================================

function Widgets.Separator()
	local w = currentWindow()
	local c = core()
	local style = c.style
	local drawList = c.drawList

	local pos = w.layout.cursor
	local clientRect = w._clientRect
	local width = Util.RectWidth(clientRect)
	local sepY = pos.Y + style.ItemSpacing.Y

	drawList:AddLine(
		Vector2_new(pos.X, sepY),
		Vector2_new(pos.X + width, sepY),
		style.Colors.Separator, 1
	)

	w.layout:ItemSize(Vector2_new(width, style.ItemSpacing.Y * 2 + 1), style.ItemSpacing)
end

-- ============================================================
-- Spacing — пустое пространство
-- ============================================================

function Widgets.Spacing()
	local w = currentWindow()
	local c = core()
	local style = c.style

	w.layout:ItemSize(Vector2_new(0, 4), style.ItemSpacing)
end

-- ============================================================
-- SameLine / Indent / Unindent — layout helpers (делегируют в Layout)
-- ============================================================

function Widgets.SameLine(offsetX: number?, spacingW: number?)
	local w = currentWindow()
	local c = core()
	w.layout:SameLine(offsetX, spacingW)
end

function Widgets.Indent(w_: number?)
	local w = currentWindow()
	local c = core()
	w.layout:Indent(w_ or c.style.IndentSpacing)
end

function Widgets.Unindent(w_: number?)
	local w = currentWindow()
	local c = core()
	w.layout:Unindent(w_ or c.style.IndentSpacing)
end

return Widgets

end)

-- ============================================================
-- Module: ImGui
-- ============================================================
define("ImGui", function(require)
-- ImGui.lua — публичный API.
-- Подключается через require(...).ImGui
-- Использование:
--
--   local ImGui = require(path.ImGui)
--   ImGui.Init()  -- однократно
--   RunService.RenderStepped:Connect(function()
--       ImGui.BeginFrame()
--       ImGui.Begin("My Window", { pos = Vector2.new(100, 100), size = Vector2.new(300, 200) })
--       ImGui.Text("hello world")
--       if ImGui.Button("press me") then print("clicked") end
--       local state = { value = false }
--       ImGui.Checkbox("enable feature", state)
--       ImGui.Separator()
--       ImGui.End()
--       ImGui.EndFrame()
--   end)
--
-- ImGui.Init() создаёт singleton-контекст (Core.new + Input.Init).

local Core    = require("Core")
local Window  = require("Window")
local Widgets = require("Widgets")
local Style   = require("Style")
local DrawList = require("DrawList")
local Input   = require("Input")
local Renderer = require("Renderer")

local ImGui = {}

-- ============================================================
-- Lifecycle
-- ============================================================

function ImGui.Init()
	local ctx = Core.Get()
	Widgets._setCoreRef(ctx)
end

function ImGui.Destroy()
	local ctx = Core.Get()
	Core.Destroy(ctx)
end

-- ============================================================
-- Frame
-- ============================================================

function ImGui.BeginFrame()
	local ctx = Core.Get()
	Core.BeginFrame(ctx)
end

function ImGui.EndFrame()
	local ctx = Core.Get()
	Core.EndFrame(ctx)
end

-- ============================================================
-- Window
-- ============================================================

-- Возвращает true если окно сейчас раскрыто (не collapsed).
function ImGui.Begin(name: string, opt: { pos: Vector2?, size: Vector2?, flags: { [string]: boolean }? }?): boolean
	local ctx = Core.Get()
	local w = Window.Begin(ctx.drawList, ctx.style, ctx.input, name, opt)
	ctx.currentWindow = w
	return not w.collapsed
end

function ImGui.End()
	local ctx = Core.Get()
	Window.End(ctx.drawList)
	ctx.currentWindow = nil
end

-- ============================================================
-- Widgets (проброс из Widgets)
-- ============================================================

ImGui.Button    = Widgets.Button
ImGui.Text      = Widgets.Text
ImGui.Checkbox  = Widgets.Checkbox
ImGui.Separator = Widgets.Separator
ImGui.Spacing   = Widgets.Spacing
ImGui.SameLine  = Widgets.SameLine
ImGui.Indent    = Widgets.Indent
ImGui.Unindent  = Widgets.Unindent

-- ============================================================
-- Style helpers
-- ============================================================

function ImGui.GetStyle(): Style.ImGuiStyle
	return Core.Get().style
end

function ImGui.PushStyleColor(name: string, color: Color3)
	-- MVP: прямая замена цвета
	local style = Core.Get().style
	style.Colors[name] = color
end

function ImGui.PopStyleColor()
	-- MVP: не реализовано, используется прямая замена
end

return ImGui

end)

-- Public entrypoint
local ImGui = _require('ImGui')
return ImGui